callback_with_context.context_function_id:
( num_units_to_upgrade = Component("units", "main_units_panel").UpgradingUnitsContextList.Size,
upgrade_cost_per_unit = CostContext.PooledResourceCostsList.FirstContext.AbsoluteValue,
faction_tally = PlayersFaction.PooledResourceContext(CostContext.PooledResourceCostsList.FirstContext.ResourceKey).Total ) =>
{
 faction_tally >= num_units_to_upgrade * upgrade_cost_per_unit
}
